/**
 * @name Path traversal in resource handler - taint flow from HTTP request to file system
 * @description User-controlled resource name or library name flows to file system operations
 * @kind path-problem
 * @problem.severity error
 * @id java/myfaces-resource-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourcePathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ClassLoader.getResource/getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // URL constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ResourcePathFlow = TaintTracking::Global<ResourcePathConfig>;
import ResourcePathFlow::PathGraph

from ResourcePathFlow::PathNode source, ResourcePathFlow::PathNode sink
where ResourcePathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: user input flows to $@.", sink.getNode(), "file system operation"

/**
 * @name Taint flow from HTTP request path to ClassLoader resource loading
 * @description Request URI components flow to ClassLoader.getResource/getResourceAsStream without path traversal validation
 * @kind path-problem
 * @problem.severity error
 * @id java/myfaces-request-to-classloader-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ClassLoaderResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Request URI / path components from servlet request
    exists(MethodCall mc |
      mc.getMethod().hasName(["getRequestURI", "getPathInfo", "getServletPath", "getRequestURL", "getParameter", "getHeader"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest")
      ) and
      source.asExpr() = mc
    )
    or
    // Also consider ExternalContext resource name methods as potential sources if they derive from request
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResourceName", "getLibraryName"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.myfaces.shared.resource", "ResourceMeta") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ExternalContext.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.faces.context", "ExternalContext") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ClassLoaderResourceFlow = TaintTracking::Global<ClassLoaderResourceConfig>;
import ClassLoaderResourceFlow::PathGraph

from ClassLoaderResourceFlow::PathNode source, ClassLoaderResourceFlow::PathNode sink
where ClassLoaderResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP request data flows to resource loading at $@.", sink.getNode(), "resource load"

/**
 * @name Full taint flow - HTTP request URI to ResourceHandlerImpl to ClassLoader
 * @description Complete path from HTTP request to resource loading via ResourceHandlerImpl
 * @kind path-problem
 * @problem.severity error
 * @id java/myfaces-full-request-to-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module FullResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getParameter calls for resource name and library name request params  
    exists(MethodCall mc |
      mc.getMethod().hasName("getParameter") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.faces.context", "ExternalContext")
      ) and
      source.asExpr() = mc
    )
    or
    // request path info / URI
    exists(MethodCall mc |
      mc.getMethod().hasName(["getRequestURI", "getPathInfo", "getServletPath"]) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.faces.context", "ExternalContext")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module FullResourceFlow = TaintTracking::Global<FullResourceConfig>;
import FullResourceFlow::PathGraph

from FullResourceFlow::PathNode source, FullResourceFlow::PathNode sink
where FullResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal from HTTP request to resource load at $@.", sink.getNode(), "resource load"

/**
 * @name Path traversal via resource name parameter in ResourceHandlerImpl
 * @description The ln (library name) and resourceName parameters from HTTP requests flow to ClassLoader.getResource without validation
 * @kind path-problem
 * @problem.severity error
 * @id java/myfaces-resource-param-to-classloader
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceParamConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ExternalContext.getResource / getResourceAsStream (filesystem)
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.faces.context", "ExternalContext") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ResourceParamFlow = TaintTracking::Global<ResourceParamConfig>;
import ResourceParamFlow::PathGraph

from ResourceParamFlow::PathNode source, ResourceParamFlow::PathNode sink
where ResourceParamFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: remote input flows to $@ without validation.", sink.getNode(), "resource loading"
